<template><div class="overlay"><form class="modal" @submit.prevent="submit"><h3>{{ t(dataset?'promptops.datasets.edit':'promptops.datasets.create') }}</h3><label>{{t('promptops.datasets.name')}}<input v-model="name" maxlength="120" required></label><label>{{t('promptops.datasets.descriptionField')}}<textarea v-model="description" maxlength="2000"/></label><p v-if="error" class="error">{{error}}</p><div class="actions"><button type="button" @click="$emit('close')">{{t('promptops.datasets.close')}}</button><button class="primary" :disabled="saving||!name.trim()">{{t('promptops.datasets.save')}}</button></div></form></div></template>
<script setup lang="ts">import{ref,watch}from'vue';import{useI18n}from'vue-i18n';import type{Dataset}from'@prompt-optimizer/core';const props=defineProps<{dataset?:Dataset;saving?:boolean}>();const emit=defineEmits<{close:[];save:[{name:string;description:string}]}>();const{t}=useI18n();const name=ref(''),description=ref(''),error=ref('');watch(()=>props.dataset,value=>{name.value=value?.name??'';description.value=value?.description??''},{immediate:true});const submit=()=>{if(!name.value.trim()){error.value=String(t('promptops.datasets.name'));return}emit('save',{name:name.value.trim(),description:description.value.trim()})}</script>
<style scoped>.overlay{position:fixed;inset:0;background:#0008;display:grid;place-items:center;z-index:30}.modal{width:min(520px,90vw);background:var(--n-color,#fff);padding:22px;border-radius:12px;display:grid;gap:14px}label{display:grid;gap:6px}input,textarea{padding:10px;border:1px solid #cbd5e1;border-radius:7px;background:inherit;color:inherit}textarea{min-height:100px}.actions{display:flex;justify-content:flex-end;gap:8px}.primary{background:#2563eb;color:#fff}.error{color:#b91c1c}</style>
